// Serves the bundled charting_library assets to the WebView over http://localhost
class LocalWebServer(private val context: Context, port: Int = 8080) : NanoHTTPD(port) {
    override fun serve(session: IHTTPSession): Response {
        val uri = if (session.uri == "/") "/index.html" else session.uri
        return try {
            val input = context.assets.open(uri.substring(1))   // assets/charting_library/...
            newChunkedResponse(Response.Status.OK, mimeOf(uri), input).apply {
                addHeader("Access-Control-Allow-Origin", "*")
            }
        } catch (e: IOException) {
            newFixedLengthResponse(Response.Status.NOT_FOUND, MIME_PLAINTEXT, "Not found")
        }
    }
}

