class TradingViewBridge(private val listener: TradingViewListener) {
    @JavascriptInterface
    fun fetchHistoricalData(paramsJson: String) {
        val p = JSONObject(paramsJson)
        listener.onHistoricalDataRequested(
            symbol = p.getString("symbol"),
            interval = p.getString("interval"),
            from = p.getLong("from"),
            to = p.getLong("to"),
            callbackKey = p.getString("callbackKey"),
        )
    }

    @JavascriptInterface
    fun searchSymbol(query: String) = listener.onSymbolSearchRequested(query)
}

function createDataFeed() {
  return {
    onReady: (cb) => setTimeout(() => cb({
      supported_resolutions: ["1","5","15","60","1D","1W","1M"],
      exchanges: [{ value: "NSE", name: "NSE", desc: "NSE India" }]
    }), 0),

    // TradingView asks for historical bars here.
    getBars: (symbolInfo, resolution, periodParams, onHistoryCallback) => {
      const { from, to } = periodParams;
      const key = symbolInfo.name + "_" + resolution + "_" + from + "_" + to;

      // getBars is synchronous, native is async ->
      // stash the callback and resolve it once Kotlin returns the data.
      pendingHistoryCallbacks.set(key, onHistoryCallback);

      window.AndroidInterface.fetchHistoricalData(JSON.stringify({
        symbol: symbolInfo.name, interval: resolution, from, to, callbackKey: key
      }));
    },

    subscribeBars: (symbolInfo, resolution, onTick, uid) =>
      subscribers.set(uid, { symbolInfo, resolution, onTick }),
    unsubscribeBars: (uid) => subscribers.delete(uid),
  };
}

override fun updateChartData(data: List<CandleData>, callbackKey: String) {
    val bars = JSONArray()
    data.forEach { c ->
        // TradingView wants SECONDS; Android gives millis -> normalize.
        val timeSec = if (c.time > 10_000_000_000L) c.time / 1000 else c.time
        bars.put(JSONObject().apply {
            put("time", timeSec); put("open", c.open); put("high", c.high)
            put("low", c.low); put("close", c.close); put("volume", c.volume)
        })
    }
    // resolve the pending getBars() callback inside the page
    val js = "updateChartData(" + bars + ", " + JSONObject.quote(callbackKey) + ")"
    webView?.evaluateJavascript(js, null)
}

class CandleAggregator {
    private val intervalSeconds = mapOf(
        "1" to 60L, "5" to 300L, "15" to 900L, "60" to 3600L, "1D" to 86_400L
    )

    // Fold a live tick into the current open candle for its interval.
    fun processTick(symbol: String, price: Double, ts: Long, interval: String): CandleData {
        val bucket = intervalSeconds.getValue(interval)
        val start = (ts / 1000 / bucket) * bucket            // align to interval
        val k = symbol + interval
        val c = active[k]
        if (c == null || start > c.time) {                  // new interval -> roll over
            active[k] = CandleData(start, price, price, price, price)
        } else {
            c.high = maxOf(c.high, price)
            c.low = minOf(c.low, price)
            c.close = price
        }
        return active.getValue(k)
    }
}

