// Trivial child + memo + useCallback that guard nothing expensive.
const Title = React.memo(function Title({ text }) {
  return <h1>{text}</h1>
})

function Page() {
  // useCallback adds dependency tracking on every render and buys nothing here.
  const onSave = useCallback(() => save(), [])
  return <Title text="Dashboard" />
}

const Row = React.memo(function Row({ item, style, onSelect }) {
  return <li style={style} onClick={() => onSelect(item.id)}>{item.name}</li>
})

function List({ items }) {
  return (
    <ul>
      {items.map((item) => (
        // New object + new function every render -> React.memo never hits.
        <Row key={item.id} item={item} style={{ padding: 8 }} onSelect={(id) => pick(id)} />
      ))}
    </ul>
  )
}

const ROW_STYLE = { padding: 8 }                 // hoisted: stable reference

function List({ items }) {
  const onSelect = useCallback((id) => pick(id), [])   // stable across renders
  return (
    <ul>
      {items.map((item) => (
        <Row key={item.id} item={item} style={ROW_STYLE} onSelect={onSelect} />
      ))}
    </ul>
  )
}

